import React from "react";
import { Link } from "react-router-dom";

const newsList = [
  {
    id: "1",
    title: "Leniency in Criminal Sentence for Justice Collaborators...",
    date: "06 February, 2025",
    excerpt: "The key to a successful criminal law enforcement depends...",
  },
  // More news...
];

function News() {
  return (
    <div className="news-list">
      {newsList.map((news) => (
        <div key={news.id} className="news-item">
          <h2>{news.title}</h2>
          <p>{news.excerpt}</p>
          <p>{news.date}</p>
          <Link to={`/news/${news.id}`}>
            <button className="read-more">Read More</button>
          </Link>
        </div>
      ))}
    </div>
  );
}

export default News;
